const { Pool } = require('pg');
const express = require('express');
const app = express();
const port = 3000;

const pool = new Pool({
  user: 'postgres',
  host: 'localhost',
  database: 'mydatabase',
  password: 'password',
  port: 5432,
});

app.use(express.json());

// Create operation
app.post('/api/:table', async (req, res) => {
  const { table } = req.params;
  const fields = Object.keys(req.body).join(', ');
  const values = Object.values(req.body);
  const placeholders = values.map((_, i) => `$${i + 1}`).join(', ');

  try {
    const result = await pool.query(`INSERT INTO ${table} (${fields}) VALUES (${placeholders}) RETURNING *`, values);
    res.json(result.rows[0]);
  } catch (err) {
    res.status(500).json(err);
  }
});

// Read operation
app.get('/api/:table/:id', async (req, res) => {
  const { table, id } = req.params;

  try {
    const result = await pool.query(`SELECT * FROM ${table} WHERE id = $1`, [id]);
    res.json(result.rows[0]);
  } catch (err) {
    res.status(500).json(err);
  }
});

// Update operation
app.put('/api/:table/:id', async (req, res) => {
  const { table, id } = req.params;
  const updates = Object.entries(req.body).map(([key, value], i) => `${key} = $${i + 1}`);
  const values = Object.values(req.body);

  try {
    const result = await pool.query(`UPDATE ${table} SET ${updates.join(', ')} WHERE id = $${values.length + 1} RETURNING *`, [...values, id]);
    res.json(result.rows[0]);
  } catch (err) {
    res.status(500).json(err);
  }
});

// Delete operation
app.delete('/api/:table/:id', async (req, res) => {
  const { table, id } = req.params;

  try {
    await pool.query(`DELETE FROM ${table} WHERE id = $1`, [id]);
    res.status(204).send();
  } catch (err) {
    res.status(500).json(err);
  }
});

app.listen(port, () => {
  console.log(`App running on port ${port}.`);
});